import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"蓝丝绒之梦","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/4.综合类/千禧骑士/套装/蓝丝绒之梦.md","filePath":"4.资源分区/1.血统与训练/4.综合类/千禧骑士/套装/蓝丝绒之梦.md"}'),s={name:"4.资源分区/1.血统与训练/4.综合类/千禧骑士/套装/蓝丝绒之梦.md"};function o(d,b,_,l,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"蓝丝绒之梦",tabindex:"-1"},[t("蓝丝绒之梦 "),r("a",{class:"header-anchor",href:"#蓝丝绒之梦","aria-label":'Permalink to "蓝丝绒之梦"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),n('<h1 id="蓝丝绒之梦-1" tabindex="-1">蓝丝绒之梦 <a class="header-anchor" href="#蓝丝绒之梦-1" aria-label="Permalink to &quot;蓝丝绒之梦&quot;">​</a></h1><p>蓝丝绒之梦</p><p>蓝丝绒之梦包括数件下属装备，仅持有【无休盛宴】或信仰雅威的单位可购买。<br> 永远无法击发的枪，永远不会射出的子弹，它的弹头停落在蓝丝绒织成的地毯上。</p><p>与火同行<br> 这是一本书页泛黄发脆的食谱，其上记载着食物的烹饪之法。翻动时，书页中发出咯吱声，就像是人类在咀嚼食物。</p><p>所有记载的【材料】皆需要消耗相应的动作放置在【无休盛宴】上才能正常使用，在生效后这一材料会在当前行动轮结束时被消耗，你无需再度购买它们，但再次使用时会消耗相应的动作。购买材料时如果不具备对应等级的相应派系造诣，则获得之。</p><p>所有材料不注明价格，均为标准价格，且正常提供自由属性，因此无法令无休盛宴武器等级提升，但能够与【无休盛宴】的【有价无市】、【不公裁判】特性正常互动。在使用时，比较重量并计算生效情况，若两端重量相等，则选择其中一项生效。</p><p>所有与火同行中记载的【材料】被视为一道法术，它们同时是【千禧骑士法术】。</p><p>D级</p><p>甘蓝<br> 价格：D+500<br> 重量：3<br> 这是一颗普通的甘蓝，还可以叫它的别名卷心菜。<br> 类型：防御技<br> 等级：D<br> 派系：自然<br> 能耗：2点能量<br> 成分：姿势<br> 动作：移动动作<br> 目标：自身<br> 持续：立即<br> 效果：当甘蓝作为较轻一端时，【有价无市】将不会使甘蓝转化为额外射程提升。进行一次格挡，并令这次格挡行为获得的防御类型改为偏斜防御，再额外获得1+传奇风度*2点偏斜防御。</p><p>土豆<br> 价格：D+500<br> 重量：5<br> 这是一颗土豆，可能烤熟了也可能没有，在某些地方备受尊重<br> 类型：攻击技<br> 等级：D<br> 派系：自然<br> 能耗：2点能量<br> 成分：姿势<br> 动作：标准动作<br> 目标：单一目标<br> 射程：同武器<br> 持续：立即<br> 效果：当土豆作为较沉一端时，正常生效。你进行一次攻击，并附带2点不可豁免疲乏异常点数和与伤害出目等额的疲乏异常点数，标准豁免。此次攻击你可以留手。</p><p>C级</p><p>胡萝卜<br> 价格：C+1000<br> 重量：5<br> 这是一根胡萝卜，据说有人为了强化视力而大量食用<br> 类型：增强技<br> 等级：C<br> 派系：自然<br> 能耗：6点能量<br> 成分：姿势<br> 动作：移动动作<br> 目标：单一目标<br> 持续：立即<br> 效果：当胡萝卜作为较沉一端时，正常生效。指定一名模糊定位或未被定位的敌人，与其进行一次侦测与反侦测对抗。对抗时你视为拥有【黑暗视觉】与【灵感视觉】，并在检定上获得2点附加成功，且本次侦测检定的【加骰等级提高一级】（至多8加骰）。</p><p>洋葱<br> 价格：C+1000<br> 重量：3<br> 这是已经被切开的一颗洋葱，总是令人泪流满面。<br> 类型：防御技<br> 等级：C<br> 派系：自然<br> 能耗：6点能量<br> 成分：姿势<br> 动作：花招动作<br> 目标：单一友方目标（包括自己）<br> 射程：触及范围<br> 持续：一场景<br> 效果：当洋葱作为较轻一端时，正常生效。指定一名友方单位，令泪水凝结而成的护盾在其周遭生成，提供6点偏斜防御且【免疫坠落伤害】，并获得【全环境呼吸】的能力持续至场景结束。</p><p>火腿<br> 价格：C+1000<br> 重量：7<br> 这是一条正在呲呲冒油的火腿，诱惑着每位瞧见的食客将其囫囵吃下，忽略了自己的口腔会被这热油烫伤<br> 类型：攻击技<br> 等级：C<br> 派系：自然<br> 能耗：6点能量<br> 成分：姿势<br> 动作：标准动作<br> 目标：单一目标<br> 持续：立即<br> 效果：当火腿作为较重一端时，正常生效。你进行一次攻击，目标以强韧豁免对抗出目，命中后施加【火焰易伤3】，其中【火焰易伤】为一场景效果。</p><p>鹅肝<br> 价格：C+1000<br> 重量：10<br> 这是一块煎烤完毕的鹅肝，因为堆满了脂肪而显得肥大，但尝起来美味便足矣。<br> 类型：防御技<br> 等级：C<br> 派系：自然<br> 能耗：6点能量<br> 成分：姿势<br> 动作：移动动作<br> 目标：自身<br> 持续：立即<br> 效果：当鹅肝作为较重一端时，才能生效。你进行一次格挡，本次格挡额外获得传奇风度*2点偏斜防御，并且使下次受到的伤害当中，至多传奇风度*2点伤害降低一级（冲击-严重-韧性）。</p><p>B级</p><p>酱汁<br> 价格：B+2000<br> 重量：0<br> 特殊的，酱汁可以与其他材料共呈一端，与酱汁共存的材料将视为+2重量。<br> 这是一些装满的瓶瓶罐罐，无论其中承载着什么，总有一个是被某些人熟知，被他们喜爱的存在。<br> 类型：应对技<br> 等级：B<br> 派系：自然<br> 能耗：10点能量<br> 成分：姿势<br> 动作：反射<br> 目标：自身<br> 持续：立即<br> 效果：当酱汁作为较重一端时，正常生效。当你在回合外遭遇一次攻击时，可使用这一技艺进行一次招架，此时你可以再额外透支下轮的标准动作，进行一次全力防御，且仅限于这次攻击获得基于偏斜防御的【坚韧】，并视为进行了一次打断（即具有打断性）。之后令你受到的这次攻击重骰取劣。<br> （这会透支你下一轮对应的AP与可转化动作上限，并且酱汁也会被从天平上拿下，当你以此法透支了下一轮的AP后，你无法继续进行透支，直到被透支的那一轮结束，你才可以继续使用本条效果）</p><p>糖<br> 价格：B+2000<br> 重量：1<br> 特殊的，糖可以与其他材料共呈一端，与糖共存的材料将视为-2重量。<br> 这是一些在某些地区是红色状的白色晶体，尝起来微甜，蕴藏着世界历史的缩影<br> 类型：应对技<br> 等级：B<br> 派系：自然<br> 能耗：10点能量<br> 成分：姿势<br> 动作：无<br> 目标：单一目标<br> 持续：立即<br> 效果：当糖作为较轻一端时，正常生效。当你在回合外遭遇一次攻击时，如果你进行了招架，则可以再额外透支下轮的标准动作，进行一次不附带任何非常态技艺的攻击，这次攻击具有【8加骰】并视为进行了一次打断（即具有打断性），自身同时往某一方向直线移动30m。<br> （这会透支你下一轮对应的AP与可转化动作上限，并且糖也会被从天平上拿下，当你以此法透支了下一轮的AP后，你无法继续进行透支，直到被透支的那一轮结束，你才可以继续使用本条效果）</p><p>橄榄<br> 价格：B+2000<br> 重量：3<br> 这是一些椭圆的果子，无论是直接品尝还是榨取出油，都有自己的受众<br> 类型：攻击技<br> 等级：B<br> 派系：自然<br> 能耗：10点能量<br> 成分：姿势<br> 动作：标准动作<br> 目标：锥形内敌方目标<br> 范围：等同射程半径的锥形<br> 持续：立即<br> 效果：当橄榄作为较轻一端时，正常生效。你进行一次范围攻击，目标以反射豁免对抗，受到差额伤害。这次攻击的伤害性质变为【火焰伤害】，若目标反射豁免失败，则受到1点不可豁免燃烧与【火焰易伤2】，其中【火焰易伤】效果持续一场景且可叠加。</p><p>A级</p><p>鱼子酱<br> 价格：A+4000<br> 重量：1<br> 特殊的，鱼子酱可以与其他材料共呈一端，与鱼子酱共存的材料将视为+7重量。<br> 这是以前奉若珍宝的珍馐，只有国力富足的君王才享福的起。同时也是上好的贡品，足矣庇护一夕安逸。<br> 类型：增强技<br> 等级：A<br> 派系：自然<br> 能耗：14点能量<br> 成分：姿势<br> 动作：移动动作<br> 目标：自身<br> 持续：一场景/鱼子酱被取下（两者取短）<br> 效果：当香料作为较沉的一方时，可以正常生效。令其生效后另一端可以放置多种材料至其重量小于香料所在的一方。根据另一端放上的材料数目与等级结算效果：<br> 根据放置的B级材料数量，当放置1/2/3件时，分别获得【劣化1】/【劣化2】/【劣化3】，皆基于偏斜防御。<br> 根据放置的C级材料数量，每有一件便获得9点偏斜防御与2点其上的附加成功。<br> 根据放置的D级材料数量，每有一件便获得40m基础移速。<br> （施法结束后，将你额外放置的材料从天平自动取下，且本场景内你不再能把它们放至天平的任何一方上与【无休盛宴】互动，除非你把鱼子酱取下）</p><p>松露<br> 价格：A+4000<br> 重量：3<br> 这是一种极其珍惜的菌类，每年都吸引着探寻美味的人入林寻找。同时还是绝佳的贡品，能够换来一季安心。<br> 类型：增强技<br> 等级：A<br> 派系：自然<br> 能耗：14点能量<br> 成分：姿势<br> 动作：移动动作<br> 目标：自身<br> 持续：一场景/松露被取下（两者取短）<br> 效果：当松露作为较轻的一方时，可以正常生效。令其生效后另一端可以放置多种材料至其重量大于松露所在的一方。根据另一端放上的材料数目与等级结算效果：<br> 根据放置的B级材料数量，当放置1/2件时，便在攻击检定上获得【毁灭】/【湮灭】，放置第3件时，每轮一次，你可以重投一次你的攻击检定，取优计算。<br> 根据放置的C级材料数量，每有一件便在攻击检定上获得6点增强加值与3点附加成功。<br> 根据放置的D级材料数量，每有一件【无休盛宴】的射程便提高40m。<br> （施法结束后，将你额外放置的材料从天平自动取下，且本场景内你不再能把它们放至天平的任何一方上与【无休盛宴】互动，除非你把松露取下）</p><p>护甲</p><p>内陆帝国</p><p>这是一件遭铁链捆绑的褴褛华服，首次购买时会提供6/6的盔甲防御，视为一件轻甲。在获得内陆帝国后，你获得下列记忆片段的购买权限。每项片段需要花费D+500如同技艺来购买获得，可以正常获得属性点。当购买的片段合计达到2/4/8时，该护甲的等级提升至C/B/A级，且盔甲防御提升至11/18/32点，视作对该护甲的升级，这会令你衣服的精细华美程度随之提高。</p><p>美丽世界<br> “我将开启新的生活，以自我毁灭的方式。”<br> 在首次见到穿戴者时，所有初次见到你且好感不低于冷漠态度的单位对你的好感都将提升1级（不可导致极端），当你在战斗外正常消耗时间以交际检定进行社交行为时，可以额外以【操控+社交+交际】对抗对方的意志豁免或是察言观色（由对方选择），若你胜出，则在这次社交行为中，只要你的提问不涉及对方的核心利益，那么这次社交行为所沟通的内容在对方的认知内将只是一次【随便聊聊】的程度，需要注意的是这一能力不会令对方对你言听计从，只是有限程度上的增加你聊天时的可涉及范围，这是一个护甲等级的心灵来源的思维控制效果。</p><p>特别嫌疑人<br> “我还站在这，是我的罪行，但也是我唯一的罪行。”<br> 选择该片段时，绑定梦力或一个你已有的互动属性为关键属性的能量池，每场影片结束时，那个能量池的上限增加3点，<br> 你获得一个无支线的信息来源的背景身份，该身份将会证明你是一名罪犯，可能是罪不至此，你暂时未被逮捕。你可以支付护甲等级点*2XP（D2C4B6A8）贿赂主神，随后该背景身份的等级提升一级，最多达到护甲等级，<br> 该背景身份为D级时，此时的身份将会显示你是一名合法且安分守己的公民，但是没有过往经历，仅附带能证明身份的物品（身份证，健康码），如果刻意去查会发现你的身份为贿赂得来，<br> 该背景身份为C级时，此时的身份将会显示你是一名政客，并附带记忆，不附带人际关系，会附带一间住所、出行工具，<br> 该背景身份为B级时，此时的身份变为你是一名地区知名政客，可能是某名议员，人们可能会记得你的名字，附带记忆，附带通常程度的人际关系，附带有限程度的正常应有的财产，<br> 该背景身份为A级时，此时的身份转变为你是一名颇具影响力的政客，人们几乎都知道你，你可能经常在电视上发表讲话或宣传造势，并自然的解释自身能力来源，且附带记忆和附带特殊渠道的人际关系，附带正常应有的财产，附带符合安排身份的消耗品（需要ST临时安排，无法带出影片）。<br> 以上所有身份，总会有一部分人知晓你曾经或仍然在收受来自各界人士的贿赂，这可能会为你带来额外的委托或者麻烦（由ST决定）。</p><p>四月<br> “哈姆雷特，在第二天到来前就已消亡。”<br> 选择该片段时，需要额外支付250分，<br> 你获得感知上的传奇属性*1点近战伤害吸收，同时获得感知上的传奇属性*1点远程伤害易伤，<br> 你的回合结束时，切换为获得感知上的传奇属性*1点远程伤害吸收，同时获得感知上的传奇属性*1点近战伤害易伤，<br> 你可以反射动作选择立刻切换一次。</p><p>幽灵情人<br> “为了寻找爱人的坟墓，我连天涯海角都走遍。”<br> 每场影片结束时，内陆帝国的护甲防御增加2点，<br> 你可以选择在主神空间额外支付4XP贿赂主神，使该护甲在下次影片结束后获得基于盔甲防御的【适应】。</p><p>无邦骑士<br> “就到这里来寻找，在岩石与海洋之间，在不安静的浪花的闪光里。”<br> 选择该片段后，获得无需休息，无需呼吸，在一场影片后，穿戴者可以知晓剧本内一个名词指向的目标的大致方位（在某个方向、某个地区），但时间上会有数周或是数月不等的误差。这是一个护甲等级的命运来源的预知效果。</p><p>再见天使<br> “没人会注意到失去一名士兵。”<br> 获得该片段后，操控检定或选择的千禧骑士攻击方式主属性上获得操控或选择的千禧骑士攻击方式主属性上的传奇属性*1点增强加值，<br> 在影片中，你可以通过口头交易或者类似方式，以提供协助等理由换取属于他人的物品的所有权，你仅能以此法收受不超过D级的物品，根据对方对于你的态度分为两种情况：<br> 若为对方主动找上你，此时对方需要以意志豁免对抗你的以操控为主属性的攻击检定，根据物品等级，你的胜出数需要超过对方至少（无支线8/D18）点才能获得这一物品的所有权，若此时你对抗失败，则由ST决定这是否属于一次敌对行为。这是一个护甲级别、信息来源的夺权效果。<br> 若此时为你以威逼利诱等方式半强制换取所有权，对方需要以意志豁免对抗你的哄骗检定【操控+社交+哄骗】，根据物品的支线等级，你的胜出数需要超过对方至少（无支线8/D18）点才能获得这一物品的所有权，若此时你对抗失败，则通常会被视作一个敌对行为从而引发战斗。这是等同于护甲支线等级、信息来源的夺权效果。<br> 每部影片你只能通过这一方式带出一件物品。</p><p>明日之战<br> “不让我安睡，也不让我唱完这首歌。”<br> 一轮一次，你可以以一个自由动作进行一次距离不超过敏捷属性*1M的移动。</p><p>额外支付D+500，不获得属性点，护甲将额外占据下装位，护甲防御增加2点，<br> 可移动的距离提升敏捷属性*2M。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',35)])])}const C=p(s,[["render",o]]);export{D as __pageData,C as default};
